// Normalize incoming ticket records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    ticketId: String(j.ticketId ?? j.id ?? '').trim(),
    subject: typeof j.subject === 'string' ? j.subject.trim() : j.subject ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

// Score each ticket 0-100 from simple heuristics
return $input.all().map(item => {
  const j = item.json;
  let score = 50;
  if (j.subject) score += 20;
  if (j.priority) score += 15;
  if ((j.source || '') === 'referral') score += 15;
  return { json: { ...j, score: Math.min(100, score) } };
});

// Round-robin owner assignment
const owners = ['ava@company.com', 'liam@company.com', 'mia@company.com'];
return $input.all().map((item, i) => ({
  json: { ...item.json, owner: owners[i % owners.length] },
}));

// Compare current metrics with the previous snapshot
const current = $input.first().json;
const prev = $('Load Previous Snapshot').first().json || {};
const drift = {};
for (const k of Object.keys(current)) {
  if (typeof current[k] === 'number' && typeof prev[k] === 'number' && prev[k] !== 0) {
    drift[k] = Math.round(((current[k] - prev[k]) / prev[k]) * 1000) / 10;
  }
}
return [{ json: { ...current, driftPct: drift, hasDrift: Object.values(drift).some(v => Math.abs(v) > 10) } }];

// Build a stable idempotency key per ticket (djb2 hash, no deps)
function hash(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16);
}
return $input.all().map(item => {
  const j = item.json;
  return { json: { ...j, idempotencyKey: hash([j.ticketId, j.subject].join('|')) } };
});
